import React from "react";
import { Icon, IconType } from "components/common/icon";
import { List, ListItem } from "components/common/newList";

import { useSiteMetadata } from "utils/graphql/queries/getSiteMetaData";
import { IconButton } from "components/common/button";

const SocialLinks = () => {
  const data = useSiteMetadata();
  const list = {
    hidden: {
      transition: {
        when: "afterChildren",
      },
    },
    visible: {
      transition: {
        when: "beforeChildren",
        staggerChildren: 0.25,
      },
    },
  };
  const itemVariants = {
    hidden: {
      opacity: 0,
      scale: 0,
    },
    visible: {
      opacity: 1,
      scale: 1,
    },
  };

  const socialListItems = data.social.map(s => {
    return (
      <ListItem variants={itemVariants}>
        <IconButton
          variant="outlined"
          size="medium"
          color={s.icon}
          hoverEffect="color"
        >
          <Icon icon={s.icon as IconType} color="inherit" />
        </IconButton>
      </ListItem>
    );
  });

  return (
    <List type="row" initial="hidden" animate="visible" variants={list}>
      {socialListItems}
    </List>
  );
};

export default SocialLinks;
